import React from 'react';

const Banner = () => {
  return (
    <section className="mb-8">
      <div className="relative w-full h-64 md:h-80 rounded-xl overflow-hidden group">
        <div className="absolute inset-0 bg-gradient-to-r from-primary to-blue-400 opacity-90"></div>
        <div className="absolute inset-0 flex flex-col justify-center px-8 md:px-16 text-white space-y-4">
          <span className="bg-white/30 backdrop-blur-sm w-fit px-3 py-1 rounded-full text-xs font-semibold uppercase tracking-wider">Mùa tựu trường 2026</span>
          <h2 className="text-3xl md:text-5xl font-bold leading-tight max-w-lg">Sắm Laptop mới <br /> Nhận ưu đãi tới 5 Triệu</h2>
          <p className="text-white/80 max-w-md">Áp dụng cho các dòng Laptop Gaming và Văn phòng cao cấp từ Dell, HP, Apple.</p>
          <button className="bg-white text-primary px-6 py-3 rounded-lg font-bold w-fit hover:bg-slate-100 transition-colors">Khám phá ngay</button>
        </div>
      </div>
    </section>
  );
};

export default Banner;
